INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (102711, 0, 311, 311002, 0, 11, "この広い会場のどこかに\nあのおかたの存在を感じますわ……", 8, 0, 0.5, 0);
