INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (100911, 0, 311, 311006, 0, 11, "疼く……疼くぞ！\n我が魔眼が新たなる年を祝えと……！", 8, 0, 0.5, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (311006, "", 311, 311007, "", 91, "", "", "", "", "");
