INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (101311, 0, 311, 311010, 0, 11, "アンナたそアンナたそ！\nおせち料理、美味しそうですぞ！\nさあ、おあがりよ！！", 8, 0, 0.5, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (311010, "", 311, 311011, "", 91, "", "", "", "", "");
