INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (105111, 0, 311, 311014, 0, 11, "医食同源……って知ってるかしら？\n長寿を願う料理には、なにかしらの\n効能があるものも多いのよ。", 8, 0, 0.5, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (311014, "", 311, 311015, "", 91, "", "", "", "", "");
