INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (101831, 0, 312, 312001, 0, 11, "素敵な新年会ね～\n他の学校の人たちも来ているようだし\nお話を伺いに行こうかしら？", 8, 0, 0.5, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (101831, "", 312, 312002, "", 3, "nop_talk_joy1", 1, 0.2, "", "");
