INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (105011, 0, 312, 312009, 0, 11, "えー？　でもあれって野菜じゃない？\n別に、大人のレディだから\n食べられないわけじゃないけど？", 8, 0, 0.5, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (105011, "", 312, 312010, "", 3, "nop_talk_sad", 1, 0.2, "", "");
