INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (105331, 0, 313, 313001, 0, 11, "立派な新年会ではないか。\n我々もこの場に相応しく\n振る舞わなければな！", 8, 0, 0.5, 0);
