INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (104731, 0, 506, 506018, 1, 11, "まあまあ、\nトモちゃんもクリスちゃんも。\nせっかくの新年会なんだから……", 8, 0, 0.5, 0);
