INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (104511, 0, 513, 513048, 1, 11, "クウカはこんな新年早々に\n豪華な料理とたくさんの人の前で\nドSさんに弄ばれ辱めを……！\nぐふふ……ぐふふふふ。", 5, 0, 0.5, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (104511, "", 513, 513049, "", 3, "nop_13_kuka_talk_memory1", 1, 0.2, "", "");
